// api/v3/handlers/addons/get.go
package addons

import (
	"context"

	apiv3 "github.com/openmeterio/openmeter/api/v3"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport"
	"github.com/openmeterio/openmeter/pkg/framework/transport/httptransport/apierrors"
)

type GetAddonRequest = apiv3.GetAddonRequestObject
type GetAddonResponse = apiv3.GetAddonResponseObject

func (h *handler) GetAddon() httptransport.Handler[GetAddonRequest, GetAddonResponse] {
	return httptransport.NewHandlerWithArgs(
		func(ctx context.Context, req GetAddonRequest) (addon.GetAddonInput, error) {
			ns, err := h.resolveNamespace(ctx)
			if err != nil {
				return addon.GetAddonInput{}, err
			}
			return addon.GetAddonInput{Namespace: ns, ID: req.AddonId}, nil
		},
		func(ctx context.Context, input addon.GetAddonInput) (addon.Addon, error) {
			return h.addonService.GetAddon(ctx, input)
		},
		func(ctx context.Context, w http.ResponseWriter, a addon.Addon) error {
			return commonhttp.JSONResponseEncoder(ctx, w, apiv3.GetAddon200JSONResponse(ToAPIAddon(a)))
		},
		httptransport.AppendOptions(
			h.options,
			httptransport.WithErrorEncoder(apierrors.GenericErrorEncoder()),
		)...,
	)
}
